backdrop-filter: blur(18px) saturate(1.5);
border: 1px solid rgba(255,255,255,0.10);
box-shadow: 0 4px 24px rgba(0,0,0,0.32), inset 0 1px 0 rgba(255,255,255,0.08);

font-variant-numeric: tabular-nums;
font-size: clamp(28px, 3.5vw, 48px);
font-weight: 800;
letter-spacing: -0.04em;
text-shadow: 0 0 24px rgba(0,212,200,0.35);

button[role='tab'][aria-selected='true'] {
  background: rgba(0,212,200,0.12);
  border-radius: 8px;
  color: #00D4C8;
  transition: background 0.25s cubic-bezier(0.22,1,0.36,1);
}

@keyframes fade-up {
  from { opacity: 0; transform: translateY(20px); }
  to   { opacity: 1; transform: translateY(0); }
}
.reveal { animation: fade-up 0.55s cubic-bezier(0.22,1,0.36,1) both; }

::-webkit-scrollbar { width: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(0,212,200,0.22); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(0,212,200,0.45); }

.signal-card::before {
  background: linear-gradient(270deg, #00D4C8, #38BDF8, #A78BFA, #00D4C8);
  background-size: 300% 300%;
  animation: border-sweep 5s ease infinite;
  -webkit-mask: linear-gradient(#fff 0 0) content-box,
                linear-gradient(#fff 0 0);
  -webkit-mask-composite: xor;
}
